package cli

import (
	"fmt"
	"io"
	"io/fs"
	"os"
	"path/filepath"
	"sort"
	"strings"

	belayer "github.com/donovan-yohan/belayer"
	"github.com/spf13/cobra"
)

// defaultConfigYAML is written to .belayer/config.yaml on first init. Runtime
// includes daemon-enforced defaults; sandbox hooks remain commented out so a
// fresh project boots with noop sandbox defaults.
const defaultConfigYAML = `# .belayer/config.yaml — runtime + sandbox configuration for this project.
# Generated by 'belayer init'. Edit freely; belayer reads this on every climb.

# Log tier. Controls how much detail flows into the event stream and archive.
#   standard — lifecycle + summaries (default; safe, small)
#   verbose  — adds raw bridge stdout + per-agent transcripts
#   trace    — adds full tool inputs/results, fs snapshots, subprocess exec
# Higher tiers increase archive size and may capture secrets; redaction is
# best-effort. See docs/LOG_FORMAT.md and docs/OBSERVABILITY.md.
log_level: standard

# Sandbox driver. The 'noop' driver runs agents in the host environment with
# no isolation. Point 'mode' at another registered driver to enable isolation.
#
# sandbox:
#   mode: noop

# Runtime hooks. Belayer can bring an integration environment up/down around
# a climb (e.g. workbench services). The live-agent caps are enforced by the
# daemon even when no runtime hooks are configured.
#
runtime:
  # Split party caps: mains are long-lived peers; sides are short-lived summons.
  max_concurrent_mains: 8
  max_concurrent_sides: 15
  max_side_summons_per_session: 30
  # up: ./scripts/workbench-up.sh
  # health: ./scripts/workbench-health.sh
  # down: ./scripts/workbench-down.sh
  # endpoints:
  #   - name: api
  #     url: http://localhost:8080

# Bridge settings. Controls how bridge subprocesses are configured.
#
# skip_openrouter_probe: when true (default), hermes-agent skips the
#   openrouter.ai metadata fetch at startup. This eliminates 20+ proxy-denied
#   CONNECTs per climb on sandboxed deployments that do not whitelist openrouter.ai.
#   Set to false only if your LLM vendor requires OpenRouter metadata at startup.
#   Note: requires a complementary hermes-agent change to take effect — see
#   docs/AGENT_ARCHITECTURE.md for details.
#
# bridge:
#   skip_openrouter_probe: true

# Exit conditions — natural-language assertions the PM validates before a climb
# is marked complete. These are the project-wide definition-of-done: the PM
# rejects completion until every condition has evidence. Edit to fit your
# workflow — PR-based teams, artifact-publishing teams, deploy-green teams,
# etc. Leave empty and the PM validates only the spec you pass at climb start.
#
# The supervisor reads this list at session start and plans toward it. The PM
# reads it during verification and will refuse completion with a specific gap
# for any condition lacking evidence.
exit_conditions:
  - "All spec acceptance criteria are implemented and verifiable in the repo"
  - "Application has been booted and primary user paths verified against the spec, with per-criterion evidence registered as a durable artifact"
  - "Code changes have been reviewed by an adversarial peer agent whose review-report artifact carries verdict NO_FINDINGS or PASS_WITH_NOTES (FAIL blocks completion)"
  - "Changes are committed to a feature branch with descriptive messages"
  - "A pull request is open against the default branch"

# Persistence strategy — the literal steps the supervisor must execute BEFORE
# reporting status=incomplete. Analog to exit_conditions, but fires on the
# escalation path: when a run cannot finish, these steps guarantee that
# in-progress work and diagnostics are saved so the next operator or retry
# has something to pick up. If the list is empty, the supervisor escalates
# immediately.
#
# The daemon intercepts a premature incomplete (no persistence-notes artifact
# registered) and reprompts the supervisor once to execute the strategy
# first. Set to [] to bypass the gate entirely.
persistence_strategy:
  - "Commit any uncommitted changes on a branch named incomplete/<session-id>"
  - "Push the branch to origin"
  - "Open a draft pull request to the default branch with a body describing: what was completed, what blocked progress, and next steps"
  - "Register a persistence-notes artifact (kind=persistence-notes) summarizing the above and linking the PR"

# Kernel-enforced write confinement for spawned agent bridges (Linux Landlock v2+).
# When true, specialists can only write under their worktree + climb dir; supervisor
# gets workspace access excluding .belayer/ runtime; all agents can write /tmp.
# Helper binary: belayer-landlock-exec must be on PATH (shipped with belayer).
# Requires Linux 5.19+ kernel; falls back to passthrough on older kernels (no hard fail).
# confine_agent_writes: true

# Extra paths specialists can write to (shared caches across worktrees). Examples:
# agent_shared_write_paths:
#   - /workspace/.cache
#   - /tmp/pnpm-store
`

func newInitCmd() *cobra.Command {
	var target string
	var force bool

	cmd := &cobra.Command{
		Use:   "init",
		Short: "Scaffold .belayer/ in the current project",
		Long: `Create .belayer/{config.yaml,agents/} in the target directory and copy
the shipped default agents (supervisor, pm, web-dev, backend-dev, qa, reviewer)
into .belayer/agents/ as a starter team.

The copied .belayer/agents/ tree is project-owned. Edit, delete, rename, or
replace those identities in the consuming repo without changing belayer source.

Idempotent: re-running prints a notice and exits 0 without overwriting. Use
--force to refresh .belayer/agents/ from the shipped defaults (useful when
upgrading belayer); existing config.yaml is never overwritten.`,
		RunE: func(cmd *cobra.Command, args []string) error {
			out := cmd.OutOrStdout()

			dir := target
			if dir == "" {
				cwd, err := os.Getwd()
				if err != nil {
					return fmt.Errorf("resolve target directory: %w", err)
				}
				dir = cwd
			}
			absDir, err := filepath.Abs(dir)
			if err != nil {
				return fmt.Errorf("resolve target directory: %w", err)
			}

			belayerDir := filepath.Join(absDir, ".belayer")
			result, err := scaffold(belayerDir, force)
			if err != nil {
				return err
			}

			if result.alreadyInitialized && !force {
				fmt.Fprintf(out, "belayer already initialized at %s\n", belayerDir)
				// Surface any upgrade changes (e.g. new .gitignore entries
				// appended on a binary bump) so the user sees them even though
				// the rest of the re-init path is silent.
				for _, line := range result.created {
					fmt.Fprintln(out, line)
				}
				return nil
			}

			for _, line := range result.created {
				fmt.Fprintln(out, line)
			}
			fmt.Fprintf(out, "\nbelayer initialized at %s (%d file(s) created)\n",
				belayerDir, len(result.created))
			return nil
		},
	}

	cmd.Flags().StringVar(&target, "target", "", "Target directory (default cwd)")
	cmd.Flags().BoolVar(&force, "force", false, "Overwrite .belayer/agents/ from shipped defaults")
	return cmd
}

// scaffoldResult records what scaffold produced so callers can render output
// (or, in the auto-init path from `belayer climb`, skip output entirely).
type scaffoldResult struct {
	alreadyInitialized bool
	created            []string
}

// scaffold creates belayerDir and its standard children. It is the core init
// routine, separated from the cobra command so `belayer climb` can call it
// directly.
//
// On re-init without --force, user-owned files (config.yaml, agents/) are not
// touched — the CLI reports "already initialized". hermes_bridge/ is no
// longer extracted here; the daemon extracts it to the runtime dir at startup
// (see internal/cli/runtime.go).
func scaffold(belayerDir string, force bool) (scaffoldResult, error) {
	var result scaffoldResult

	if info, err := os.Stat(belayerDir); err == nil {
		if !info.IsDir() {
			return result, fmt.Errorf("%s exists but is not a directory", belayerDir)
		}
		result.alreadyInitialized = true
	} else if !os.IsNotExist(err) {
		return result, fmt.Errorf("stat %s: %w", belayerDir, err)
	}

	for _, sub := range []string{"", "agents"} {
		p := filepath.Join(belayerDir, sub)
		if err := os.MkdirAll(p, 0o755); err != nil {
			return result, fmt.Errorf("mkdir %s: %w", p, err)
		}
	}

	// Gitignore maintenance runs before the re-init early return so that
	// binary upgrades which add new entries land in already-initialized
	// projects, not just fresh ones.
	gitignoreNote, err := ensureGitignoreEntries(filepath.Dir(belayerDir))
	if err != nil {
		return result, err
	}
	if gitignoreNote != "" {
		result.created = append(result.created, gitignoreNote)
	}

	// If already initialized and not --force, stop here — user-owned files
	// (config.yaml, agents/) remain untouched.
	if result.alreadyInitialized && !force {
		sort.Strings(result.created)
		return result, nil
	}

	configPath := filepath.Join(belayerDir, "config.yaml")
	if created, err := writeIfMissing(configPath, []byte(defaultConfigYAML)); err != nil {
		return result, err
	} else if created {
		result.created = append(result.created, "  + "+relativize(belayerDir, configPath))
	}

	agentsRoot := filepath.Join(belayerDir, "agents")
	copied, err := copyDefaultAgents(agentsRoot, force)
	if err != nil {
		return result, err
	}
	for _, p := range copied {
		result.created = append(result.created, "  + "+relativize(belayerDir, p))
	}

	sort.Strings(result.created)

	return result, nil
}

// gitignoreHeader labels the belayer-managed block. Kept as a named constant
// so the marker check below can match on it exactly, and so later versions can
// append a second labelled block for entries added on upgrade.
//
// Entries in gitignoreEntries are anchored with a leading slash so they only
// match at the repo root — nested .belayer/ inside subprojects (e.g. inside
// .belayer/worktrees/...) are not affected by these rules.
//
// Note: .belayer/ contains per-climb state (climbs/, legacy runs/, worktrees/) that is machine-
// generated and should not be committed. The hermes_bridge Python package is
// NOT stored here — it lives in the daemon's runtime dir
// (default $XDG_STATE_HOME/belayer/runtime) so workspace agents cannot destroy
// it. Only agents/ and config.yaml are committed.
const (
	gitignoreHeader        = "# belayer — per-climb state (.belayer/ contains climbs/, legacy runs/, and worktrees/; hermes_bridge is in runtime dir)"
	gitignoreUpgradeHeader = "# belayer — added on upgrade"
	gitignoreMarker        = "# belayer — per-climb state"
	legacyGitignoreMarker  = "# belayer — per-run state"
)

var gitignoreEntries = []string{
	"/.belayer/climbs/",
	"/.belayer/runs/",
	"/.belayer/worktrees/",
}

// ensureGitignoreEntries makes sure every entry in gitignoreEntries is present
// in <project>/.gitignore. On a fresh file (or one without the belayer marker)
// it writes the full labelled block. On upgrades — marker present but a newer
// belayer release introduced an entry — it appends the missing entries under
// an "added on upgrade" label so their provenance is visible. Returns a
// one-line summary describing what changed, or "" when no change was needed.
// Never modifies an existing line — only appends.
func ensureGitignoreEntries(projectDir string) (string, error) {
	path := filepath.Join(projectDir, ".gitignore")
	existing, err := os.ReadFile(path)
	if err != nil && !os.IsNotExist(err) {
		return "", fmt.Errorf("read %s: %w", path, err)
	}

	present := map[string]bool{}
	for _, line := range strings.Split(string(existing), "\n") {
		present[strings.TrimSpace(line)] = true
	}

	var missing []string
	for _, entry := range gitignoreEntries {
		if !present[entry] {
			missing = append(missing, entry)
		}
	}
	if len(missing) == 0 {
		return "", nil
	}

	fresh := len(existing) == 0
	markerPresent := strings.Contains(string(existing), gitignoreMarker) || strings.Contains(string(existing), legacyGitignoreMarker)

	out := append([]byte{}, existing...)
	if !fresh {
		if out[len(out)-1] != '\n' {
			out = append(out, '\n')
		}
		// Separator blank line before the belayer block so it doesn't merge
		// visually into whatever the user had above.
		out = append(out, '\n')
	}

	switch {
	case !markerPresent:
		out = append(out, []byte(gitignoreHeader+"\n")...)
	default:
		// Marker already present but new entries surfaced in a later release.
		// Label the upgrade block so users can see where these came from.
		out = append(out, []byte(gitignoreUpgradeHeader+"\n")...)
	}
	for _, entry := range missing {
		out = append(out, []byte(entry+"\n")...)
	}

	if err := os.WriteFile(path, out, 0o644); err != nil {
		return "", fmt.Errorf("write %s: %w", path, err)
	}
	switch {
	case fresh:
		return "  + .gitignore (created with belayer entries)", nil
	case !markerPresent:
		return "  ~ .gitignore (appended belayer entries)", nil
	default:
		return "  ~ .gitignore (appended missing belayer entries on upgrade)", nil
	}
}

// copyDefaultAgents walks the embedded agents/ tree and writes each file into
// dst. Files that already exist are skipped unless force is set, in which case
// they are overwritten — this is how `belayer init --force` upgrades a
// project's shipped agents while leaving user-added profiles intact.
func copyDefaultAgents(dst string, force bool) ([]string, error) {
	var written []string
	err := fs.WalkDir(belayer.DefaultAgents, "agents", func(path string, d fs.DirEntry, walkErr error) error {
		if walkErr != nil {
			return walkErr
		}
		// "agents" itself is the embed root; skip it — we already created dst.
		if path == "agents" {
			return nil
		}
		// Strip the leading "agents/" so paths land directly under dst.
		rel := strings.TrimPrefix(path, "agents/")
		out := filepath.Join(dst, rel)

		if d.IsDir() {
			if err := os.MkdirAll(out, 0o755); err != nil {
				return fmt.Errorf("mkdir %s: %w", out, err)
			}
			return nil
		}

		if !force {
			if _, err := os.Stat(out); err == nil {
				return nil
			} else if !os.IsNotExist(err) {
				return fmt.Errorf("stat %s: %w", out, err)
			}
		}

		data, err := belayer.DefaultAgents.ReadFile(path)
		if err != nil {
			return fmt.Errorf("read embedded %s: %w", path, err)
		}
		if err := os.WriteFile(out, data, 0o644); err != nil {
			return fmt.Errorf("write %s: %w", out, err)
		}
		written = append(written, out)
		return nil
	})
	if err != nil {
		return nil, err
	}
	return written, nil
}

// writeIfMissing writes data to path only if path does not already exist.
// Returns true when a file was created, false when one was already present.
// Existing files are never touched — config.yaml is user-owned once init
// has run.
func writeIfMissing(path string, data []byte) (bool, error) {
	if _, err := os.Stat(path); err == nil {
		return false, nil
	} else if !os.IsNotExist(err) {
		return false, fmt.Errorf("stat %s: %w", path, err)
	}
	if err := os.WriteFile(path, data, 0o644); err != nil {
		return false, fmt.Errorf("write %s: %w", path, err)
	}
	return true, nil
}

// relativize trims a leading parent prefix from p so output paths stay short.
// It falls back to p when the prefix does not match.
func relativize(parent, p string) string {
	rel, err := filepath.Rel(filepath.Dir(parent), p)
	if err != nil {
		return p
	}
	return rel
}

// autoInitIfMissing is the entry point for `belayer climb` to scaffold .belayer/
// without forcing the user to call `belayer init` first. On a fresh scaffold
// (no prior .belayer/) a notice is written to w; re-init on existing projects
// is silent to avoid log spam on the hot path.
// Note: hermes_bridge extraction is no longer done here — the daemon handles
// it at startup via extractBridgeToRuntimeDir.
func autoInitIfMissing(workdir string, w io.Writer) error {
	belayerDir := filepath.Join(workdir, ".belayer")
	result, err := scaffold(belayerDir, false)
	if err != nil {
		return err
	}
	if !result.alreadyInitialized {
		fmt.Fprintf(w, "Auto-initialized %s with default agents — review and tweak as needed before next climb.\n", belayerDir)
	}
	return nil
}
